1	// Compile-time layout lock for hybrid_state_v1.
2	//
3	// Any drift in the offset of a published field, or a size change to an array,
4	// breaks every translation unit that includes state_abi.h. This is the
5	// intended behaviour: the ABI is a wire contract.
6	//
7	// Adding a NEW field consumes bytes from `reserved`; the existing asserts must
8	// continue to hold and a new assert is added for the new field.
9	
10	#ifndef HYBRID_STATE_ABI_CHECK_H
11	#define HYBRID_STATE_ABI_CHECK_H
12	
13	#include "hybrid/state_abi.h"
14	
15	#if defined(__cplusplus)
16	#  define HYBRID_STATIC_ASSERT(expr, msg) static_assert((expr), msg)
17	#else
18	#  define HYBRID_STATIC_ASSERT(expr, msg) _Static_assert((expr), msg)
19	#endif
20	
21	// Header
22	HYBRID_STATIC_ASSERT(offsetof(struct hybrid_state_v1, magic)   == 0,  "magic@0");
23	HYBRID_STATIC_ASSERT(offsetof(struct hybrid_state_v1, version) == 4,  "version@4");
24	HYBRID_STATIC_ASSERT(offsetof(struct hybrid_state_v1, flags)   == 8,  "flags@8");
25	HYBRID_STATIC_ASSERT(offsetof(struct hybrid_state_v1, hart_id) == 12, "hart_id@12");
26	HYBRID_STATIC_ASSERT(offsetof(struct hybrid_state_v1, pc)      == 16, "pc@16");
27	HYBRID_STATIC_ASSERT(offsetof(struct hybrid_state_v1, priv)    == 24, "priv@24");
28	
29	// Register files
30	HYBRID_STATIC_ASSERT(offsetof(struct hybrid_state_v1, gpr) == 32,  "gpr@32");
31	HYBRID_STATIC_ASSERT(offsetof(struct hybrid_state_v1, fpr) == 288, "fpr@288");
32	
33	// CSRs (M-mode)
34	HYBRID_STATIC_ASSERT(offsetof(struct hybrid_state_v1, mstatus)  == 544, "mstatus@544");
35	HYBRID_STATIC_ASSERT(offsetof(struct hybrid_state_v1, mepc)     == 552, "mepc@552");
36	HYBRID_STATIC_ASSERT(offsetof(struct hybrid_state_v1, mtvec)    == 560, "mtvec@560");
37	HYBRID_STATIC_ASSERT(offsetof(struct hybrid_state_v1, mcause)   == 568, "mcause@568");
38	HYBRID_STATIC_ASSERT(offsetof(struct hybrid_state_v1, mtval)    == 576, "mtval@576");
39	HYBRID_STATIC_ASSERT(offsetof(struct hybrid_state_v1, mscratch) == 584, "mscratch@584");
40	HYBRID_STATIC_ASSERT(offsetof(struct hybrid_state_v1, medeleg)  == 592, "medeleg@592");
41	HYBRID_STATIC_ASSERT(offsetof(struct hybrid_state_v1, mideleg)  == 600, "mideleg@600");
42	HYBRID_STATIC_ASSERT(offsetof(struct hybrid_state_v1, mip)      == 608, "mip@608");
43	HYBRID_STATIC_ASSERT(offsetof(struct hybrid_state_v1, mie)      == 616, "mie@616");
44	HYBRID_STATIC_ASSERT(offsetof(struct hybrid_state_v1, mcycle)   == 624, "mcycle@624");
45	HYBRID_STATIC_ASSERT(offsetof(struct hybrid_state_v1, minstret) == 632, "minstret@632");
46	HYBRID_STATIC_ASSERT(offsetof(struct hybrid_state_v1, satp)     == 640, "satp@640");
47	
48	// PMP
49	HYBRID_STATIC_ASSERT(offsetof(struct hybrid_state_v1, pmpcfg)  == 648, "pmpcfg@648");
50	HYBRID_STATIC_ASSERT(offsetof(struct hybrid_state_v1, pmpaddr) == 776, "pmpaddr@776");
51	
52	// V-extension
53	HYBRID_STATIC_ASSERT(offsetof(struct hybrid_state_v1, vstart) == 1288, "vstart@1288");
54	HYBRID_STATIC_ASSERT(offsetof(struct hybrid_state_v1, vtype)  == 1296, "vtype@1296");
55	HYBRID_STATIC_ASSERT(offsetof(struct hybrid_state_v1, vl)     == 1304, "vl@1304");
56	HYBRID_STATIC_ASSERT(offsetof(struct hybrid_state_v1, vlenb)  == 1312, "vlenb@1312");
57	HYBRID_STATIC_ASSERT(offsetof(struct hybrid_state_v1, vreg)   == 1320, "vreg@1320");
58	
59	// Reserved + total size
60	HYBRID_STATIC_ASSERT(offsetof(struct hybrid_state_v1, reserved) == 5416, "reserved@5416");
61	HYBRID_STATIC_ASSERT(sizeof(struct hybrid_state_v1) == 5672, "hybrid_state_v1 total size");
62	
63	// Sub-array sizes
64	HYBRID_STATIC_ASSERT(HYBRID_VLEN_BYTES_MAX == 128, "VLEN bytes pinned to 1024-bit");
65	HYBRID_STATIC_ASSERT(HYBRID_PMP_CFG_NUM == 16,     "pmpcfg slot count");
66	HYBRID_STATIC_ASSERT(HYBRID_PMP_ADDR_NUM == 64,    "pmpaddr entry count");
67	
68	#endif  // HYBRID_STATE_ABI_CHECK_H
