1	// Phase 0.1 RED: ABI contract for hybrid handoff state.
2	// Locks magic/version constants, struct layout, and byte-level roundtrip.
3	// state_abi.h does not exist yet -- this file MUST fail to compile until it does.
4	
5	#include "hybrid/state_abi.h"
6	
7	#define DOCTEST_CONFIG_IMPLEMENT_WITH_MAIN
8	#include <doctest.h>
9	
10	#include <cstdint>
11	#include <cstring>
12	#include <type_traits>
13	
14	TEST_CASE("magic and version are stable wire constants")
15	{
16	  // 'AHYB' read little-endian: 'A'=0x41 'H'=0x48 'Y'=0x59 'B'=0x42
17	  CHECK(HYBRID_STATE_MAGIC == 0x42594841u);
18	  CHECK(HYBRID_STATE_VERSION == 1u);
19	}
20	
21	TEST_CASE("struct is standard-layout, trivially copyable, packed")
22	{
23	  CHECK(std::is_standard_layout_v<hybrid_state_v1>);
24	  CHECK(std::is_trivially_copyable_v<hybrid_state_v1>);
25	  // packed: fields are 8-byte aligned naturally, so packing should not shrink
26	  // sizeof. We assert no implicit tail padding either.
27	  CHECK(sizeof(hybrid_state_v1) % 8 == 0);
28	}
29	
30	TEST_CASE("header field offsets")
31	{
32	  CHECK(offsetof(hybrid_state_v1, magic) == 0);
33	  CHECK(offsetof(hybrid_state_v1, version) == 4);
34	  CHECK(offsetof(hybrid_state_v1, flags) == 8);
35	  CHECK(offsetof(hybrid_state_v1, hart_id) == 12);
36	  CHECK(offsetof(hybrid_state_v1, pc) == 16);
37	  CHECK(offsetof(hybrid_state_v1, priv) == 24);
38	}
39	
40	TEST_CASE("GPR and FPR are 32 * uint64_t each, contiguous")
41	{
42	  CHECK(offsetof(hybrid_state_v1, gpr) == 32);
43	  CHECK(sizeof(((hybrid_state_v1*) 0)->gpr) == 32 * sizeof(uint64_t));
44	  CHECK(offsetof(hybrid_state_v1, fpr) == 32 + 32 * 8);
45	  CHECK(sizeof(((hybrid_state_v1*) 0)->fpr) == 32 * sizeof(uint64_t));
46	}
47	
48	TEST_CASE("V-extension fields use compile-time MAX_VLEN constant")
49	{
50	  CHECK(HYBRID_VLEN_BYTES_MAX >= 16);  // RVV minimum VLEN=128 -> 16 bytes
51	  CHECK((HYBRID_VLEN_BYTES_MAX & (HYBRID_VLEN_BYTES_MAX - 1)) == 0);  // power of 2
52	  CHECK(sizeof(((hybrid_state_v1*) 0)->vreg) == 32u * HYBRID_VLEN_BYTES_MAX);
53	}
54	
55	TEST_CASE("PMP arrays are sized per spec")
56	{
57	  CHECK(sizeof(((hybrid_state_v1*) 0)->pmpcfg) == HYBRID_PMP_CFG_NUM * sizeof(uint64_t));
58	  CHECK(sizeof(((hybrid_state_v1*) 0)->pmpaddr) == HYBRID_PMP_ADDR_NUM * sizeof(uint64_t));
59	  CHECK(HYBRID_PMP_ADDR_NUM == 64);
60	  CHECK(HYBRID_PMP_CFG_NUM == 16);
61	}
62	
63	TEST_CASE("trailing reserved padding is at least 256 bytes")
64	{
65	  CHECK(sizeof(((hybrid_state_v1*) 0)->reserved) >= 256);
66	}
67	
68	TEST_CASE("byte-level roundtrip via memcpy preserves all fields")
69	{
70	  hybrid_state_v1 src{};
71	  src.magic = HYBRID_STATE_MAGIC;
72	  src.version = HYBRID_STATE_VERSION;
73	  src.flags = HYBRID_FLAG_RV64 | HYBRID_FLAG_FP | HYBRID_FLAG_V;
74	  src.hart_id = 1;
75	  src.pc = 0x80001234ULL;
76	  src.priv = 3;  // M-mode
77	
78	  for (int i = 0; i < 32; ++i) {
79	    src.gpr[i] = 0xCAFE0000ULL + i;
80	    src.fpr[i] = 0xF00D0000ULL + i;
81	  }
82	  src.mstatus = 0xa00040080ULL;
83	  src.mepc    = 0x80002000ULL;
84	  src.mtvec   = 0x80000000ULL;
85	  src.satp    = 0x8000000000080000ULL;
86	  src.vstart  = 0;
87	  src.vtype   = 0xc0;
88	  src.vl      = 4;
89	  src.vlenb   = 16;
90	  for (size_t i = 0; i < sizeof(src.vreg); ++i) src.vreg[i] = (uint8_t) i;
91	
92	  alignas(hybrid_state_v1) unsigned char buf[sizeof(hybrid_state_v1)];
93	  std::memcpy(buf, &src, sizeof(src));
94	  hybrid_state_v1 dst{};
95	  std::memcpy(&dst, buf, sizeof(dst));
96	
97	  CHECK(dst.magic == HYBRID_STATE_MAGIC);
98	  CHECK(dst.version == HYBRID_STATE_VERSION);
99	  CHECK(dst.flags == src.flags);
100	  CHECK(dst.hart_id == 1);
101	  CHECK(dst.pc == 0x80001234ULL);
102	  CHECK(dst.priv == 3);
103	  for (int i = 0; i < 32; ++i) {
104	    CHECK(dst.gpr[i] == 0xCAFE0000ULL + i);
105	    CHECK(dst.fpr[i] == 0xF00D0000ULL + i);
106	  }
107	  CHECK(dst.mstatus == 0xa00040080ULL);
108	  CHECK(dst.mepc == 0x80002000ULL);
109	  CHECK(dst.mtvec == 0x80000000ULL);
110	  CHECK(dst.satp == 0x8000000000080000ULL);
111	  CHECK(dst.vtype == 0xc0);
112	  CHECK(dst.vl == 4);
113	  CHECK(dst.vlenb == 16);
114	  CHECK(std::memcmp(dst.vreg, src.vreg, sizeof(src.vreg)) == 0);
115	}
116	
117	TEST_CASE("flag bits are stable wire constants")
118	{
119	  CHECK(HYBRID_FLAG_RV64 == (1u << 0));
120	  CHECK(HYBRID_FLAG_FP   == (1u << 1));
121	  CHECK(HYBRID_FLAG_V    == (1u << 2));
122	}
